class Solution:
    def matchPlayersAndTrainers(self, players, trainers):
        players = sorted(players)
        trainers = sorted(trainers)
        used = [False] * len(trainers)
        count = 0
        for p in players:
            for j in range(len(trainers)):
                if not used[j] and trainers[j] >= p:
                    used[j] = True
                    count += 1
                    break
        return count

